// --- MENU INTERFACES ---
interface MenuItem {
  id: number
  name: string
  category: string
  description: string
  image: string
  price: number
  availability: boolean
  veg: boolean      // true for Veg (green dot), false for Non-Veg (red dot)
  popular?: boolean // true if shown in the horizontal popular slider
}

// --- CART INTERFACES ---
interface CartItem {
  item: MenuItem
  quantity: number
  activePrice: number
}

interface SupabaseOrder {
  id: string
  customer_name: string
  phone: string
  item_summary: string
  items: CartItem[]
  subtotal: number
  packaging: number
  total: number
  payment_status: string
  order_status: string
  maps_link: string
  created_at: string
}

